CREATE OR REPLACE FUNCTION document_qa.seed_confirmation_doe()
 RETURNS uuid
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_c uuid; v_g uuid;
  v_w constant real := 210;
  v_h constant real := 297;
  v_primary constant text := '#033345';
  v_red constant text := '#e53150';
