  SELECT id INTO v_bg_id FROM document.brand_guide WHERE name = 'My French Tour' AND tenant_id = 'dev';

  v_c := document.canvas_create('Confirmation — John & Jane Doe', 'A4', 'portrait', v_w, v_h, v_cream, 'confirmation');

