  END IF;
  v_so := v_so + 1;

  PERFORM document.element_add(v_c, 'rect', v_so, jsonb_build_object('x',0,'y',55,'width',v_w,'height',30,'fill',v_primary,'opacity',0.75,'name','bandeau'));
